"use client";

import { memo, useId, useMemo } from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_PEOPLE_GRID_LABELS,
  type PeopleGrid01Columns,
  type PeopleGrid01Labels,
  type PeopleGrid01Props,
} from "./types";
import { PersonCard } from "./parts/person-card";

const COLUMNS_MAP: Record<PeopleGrid01Columns, string> = {
  2: "grid-cols-1 sm:grid-cols-2",
  3: "grid-cols-1 sm:grid-cols-2 md:grid-cols-3",
  4: "grid-cols-1 sm:grid-cols-2 md:grid-cols-4",
  5: "grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-5",
};

function PeopleGrid01Inner({
  items,
  heading,
  headingAs = "h2",
  columns = 3,
  avatarSize = "lg",
  alignment = "center",
  linkComponent = "a",
  renderItem,
  labels: labelsProp,
  emptyState,
  className,
  headingClassName,
  gridClassName,
  itemClassName,
}: PeopleGrid01Props) {
  const headingId = useId();
  const HeadingTag = headingAs;

  const labels = useMemo<Required<PeopleGrid01Labels>>(
    () => ({ ...DEFAULT_PEOPLE_GRID_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const isEmpty = items.length === 0;

  return (
    <section
      aria-labelledby={heading ? headingId : undefined}
      className={cn("space-y-6", className)}
    >
      {heading && (
        <HeadingTag
          id={headingId}
          className={cn(
            "text-2xl font-bold text-foreground",
            headingClassName,
          )}
        >
          {heading}
        </HeadingTag>
      )}

      {isEmpty ? (
        emptyState ?? (
          <p
            role="status"
            className="text-sm text-muted-foreground"
          >
            {labels.emptyText}
          </p>
        )
      ) : (
        <ul
          role="list"
          className={cn("grid gap-6", COLUMNS_MAP[columns], gridClassName)}
        >
          {items.map((item) =>
            renderItem ? (
              <li key={item.id}>{renderItem(item)}</li>
            ) : (
              <PersonCard
                key={item.id}
                item={item}
                avatarSize={avatarSize}
                alignment={alignment}
                linkComponent={linkComponent}
                itemClassName={itemClassName}
              />
            ),
          )}
        </ul>
      )}
    </section>
  );
}

const PeopleGrid01 = memo(PeopleGrid01Inner);
PeopleGrid01.displayName = "PeopleGrid01";

export { PeopleGrid01 };
export default PeopleGrid01;

export { PeopleGrid01, default } from "./people-grid-01";

export type {
  PeopleGridItem,
  PeopleGrid01Labels,
  PeopleGrid01Props,
  PeopleGrid01Columns,
  PeopleGrid01AvatarSize,
  PeopleGrid01Alignment,
} from "./types";

export { DEFAULT_PEOPLE_GRID_LABELS } from "./types";

export { getInitials } from "./lib/get-initials";

import type { ElementType, ReactNode } from "react";

export type PeopleGrid01Columns = 2 | 3 | 4 | 5;
export type PeopleGrid01AvatarSize = "sm" | "md" | "lg";
export type PeopleGrid01Alignment = "center" | "start";

export interface PeopleGridItem {
  /** Stable identifier. Used for React keys + accessible-name composition. */
  id: string;
  /** Person's display name. Required — drives the initials fallback. */
  name: string;
  /** Role / title (muted, smaller, below name). Optional. */
  title?: string;
  /** Avatar image URL. Optional — falls back to initials circle. */
  image?: string;
  /** Image alt text. Optional — falls back to `name`. */
  imageAlt?: string;
  /** Optional URL — when supplied + `linkComponent` provided, the entire card becomes clickable. */
  href?: string;
}

export interface PeopleGrid01Labels {
  /** Default: "No people to display." Used when `items` is empty AND `emptyState` not provided. */
  emptyText?: string;
}

export interface PeopleGrid01Props {
  /** Items to render in display order. */
  items: PeopleGridItem[];

  /** Optional section heading text. */
  heading?: string;
  /** Heading semantic level. Default: 'h2' (people grids are typically top-level page sections). */
  headingAs?: "h2" | "h3" | "h4";

  /** Number of columns at the largest breakpoint. Default: 3. All grids start at 1 col on mobile. */
  columns?: PeopleGrid01Columns;
  /** Avatar size. Default: 'lg' (w-24 h-24). 'md' = w-16, 'sm' = w-12. */
  avatarSize?: PeopleGrid01AvatarSize;
  /** Card alignment within each grid cell. Default: 'center'. */
  alignment?: PeopleGrid01Alignment;

  /** Element used when `item.href` is supplied. Default: 'a'. */
  linkComponent?: ElementType;

  /** Custom per-item renderer — bypasses the default card layout entirely. */
  renderItem?: (item: PeopleGridItem) => ReactNode;

  /** Localized labels. */
  labels?: PeopleGrid01Labels;

  /** Empty-state slot. Wins over `labels.emptyText`. */
  emptyState?: ReactNode;

  /** Override classes for the root <section>. */
  className?: string;
  /** Override classes for the heading. */
  headingClassName?: string;
  /** Override classes for the grid container. */
  gridClassName?: string;
  /** Override classes per item (the <li>). */
  itemClassName?: string;
}

/** Default English labels — exported for consumer composition. */
export const DEFAULT_PEOPLE_GRID_LABELS: Required<PeopleGrid01Labels> = {
  emptyText: "No people to display.",
};

"use client";

import { useId, type ElementType } from "react";
import { cn } from "@/lib/utils";
import type {
  PeopleGrid01Alignment,
  PeopleGrid01AvatarSize,
  PeopleGridItem,
} from "../types";
import { getInitials } from "../lib/get-initials";

interface PersonCardProps {
  item: PeopleGridItem;
  avatarSize: PeopleGrid01AvatarSize;
  alignment: PeopleGrid01Alignment;
  linkComponent: ElementType;
  itemClassName?: string;
}

const AVATAR_SIZE_MAP: Record<
  PeopleGrid01AvatarSize,
  { wrapper: string; initials: string }
> = {
  sm: { wrapper: "w-12 h-12", initials: "text-sm" },
  md: { wrapper: "w-16 h-16", initials: "text-base" },
  lg: { wrapper: "w-24 h-24", initials: "text-2xl" },
};

export function PersonCard({
  item,
  avatarSize,
  alignment,
  linkComponent: LinkComponent,
  itemClassName,
}: PersonCardProps) {
  const nameId = useId();
  const isLinked = item.href != null && item.href.length > 0;
  const sizeClasses = AVATAR_SIZE_MAP[avatarSize];

  return (
    <li
      className={cn(
        "relative group",
        alignment === "center" ? "text-center" : "text-start",
        itemClassName,
      )}
    >
      <div
        className={cn(
          "rounded-full overflow-hidden border-4 border-primary/20 mb-3",
          sizeClasses.wrapper,
          alignment === "center" ? "mx-auto" : "",
        )}
      >
        {item.image ? (
          <img
            src={item.image}
            alt={item.imageAlt ?? item.name}
            loading="lazy"
            className="w-full h-full object-cover"
          />
        ) : (
          <div
            aria-hidden="true"
            className={cn(
              "w-full h-full flex items-center justify-center bg-primary/10 text-primary font-semibold",
              sizeClasses.initials,
            )}
          >
            {getInitials(item.name)}
          </div>
        )}
      </div>

      <h4
        id={nameId}
        className="font-semibold text-foreground motion-safe:group-hover:text-primary transition-colors"
      >
        {item.name}
      </h4>
      {item.title && (
        <p className="text-sm text-muted-foreground">{item.title}</p>
      )}

      {isLinked && (
        <LinkComponent
          href={item.href}
          aria-labelledby={nameId}
          className="absolute inset-0 z-0 outline-none rounded-lg focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
        />
      )}
    </li>
  );
}

const TITLE_PATTERN = /^(Dr|Prof|Mr|Mrs|Ms|Sr|Jr)\.?$/i;

/**
 * Pure function. Returns 1–2 uppercase initials from a name.
 *
 * Skips common honorifics (Dr., Prof., Mr., Mrs., Ms., Sr., Jr.).
 *
 * @example
 * getInitials("Dr. Ahmet Yılmaz")    // → "AY"
 * getInitials("Prof. Dr. Elif Kaya") // → "EK"
 * getInitials("Madonna")             // → "M"
 * getInitials("")                    // → "?"
 */
export function getInitials(name: string): string {
  const trimmed = name.trim();
  if (!trimmed) return "?";

  const parts = trimmed
    .split(/\s+/)
    .filter((p) => !TITLE_PATTERN.test(p));

  if (parts.length === 0) {
    return trimmed.charAt(0).toUpperCase() || "?";
  }
  if (parts.length === 1) {
    return parts[0].charAt(0).toUpperCase();
  }
  return (
    parts[0].charAt(0) + parts[parts.length - 1].charAt(0)
  ).toUpperCase();
}
